/**
 * @name Dynamic class loading with user-controlled class name
 * @description Class.forName() or ClassLoader.loadClass() with user-controlled class names enables arbitrary code execution
 * @kind path-problem
 * @problem.severity error
 * @id java/dynamic-class-loading-user-input
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DynamicClassLoadingConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Class.forName(className)
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClassLoader.loadClass(className)
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module DynamicClassLoadingFlow = TaintTracking::Global<DynamicClassLoadingConfig>;
import DynamicClassLoadingFlow::PathGraph

from DynamicClassLoadingFlow::PathNode source, DynamicClassLoadingFlow::PathNode sink
where DynamicClassLoadingFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Dynamic class loading with user-controlled class name from $@.", source.getNode(), "user input"

/**
 * @name User-controlled property type class name via REST API (CWE-470)
 * @description HTTP API accepts a property 'type' field as class name that flows to Class.forName()
 *              enabling arbitrary class loading and instantiation
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-property-type-class-injection
 * @tags security
 *       external/cwe/cwe-470
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PropertyTypeClassInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isAdditionalFlowStep(DataFlow::Node n1, DataFlow::Node n2) {
    // PropertyApiBean.toProperty() / fromProperty() - type field to PropertyFactory
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.ff4j.web.api.resources.domain", "PropertyApiBean") and
      n1.asExpr() = mc.getAnArgument() and
      n2.asExpr() = mc
    )
  }
}

module PropertyTypeClassInjectionFlow = TaintTracking::Global<PropertyTypeClassInjectionConfig>;
import PropertyTypeClassInjectionFlow::PathGraph

from PropertyTypeClassInjectionFlow::PathNode source, PropertyTypeClassInjectionFlow::PathNode sink
where PropertyTypeClassInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled property type class name from $@ flows to Class.forName().", source.getNode(), "HTTP input"

/**
 * @name Unvalidated redirect in ff4j web module
 * @description User-controlled redirect URL without validation
 * @kind path-problem
 * @problem.severity error
 * @id java/ff4j-open-redirect
 * @tags security
 *       external/cwe/cwe-601
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module OpenRedirectConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("sendRedirect") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletResponse") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module OpenRedirectFlow = TaintTracking::Global<OpenRedirectConfig>;
import OpenRedirectFlow::PathGraph

from OpenRedirectFlow::PathNode source, OpenRedirectFlow::PathNode sink
where OpenRedirectFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to sendRedirect() from $@ - potential open redirect.", source.getNode(), "user input"
